#define VVLL vector<vector<LL>>
#define VI vector<int>
#define VLL vector<LL>
#define VPII vector<pair<int, int>>
#define VPLL vector<pair<LL, LL>>


const int N = 1e5 + 10;

void solve()
{
    int n, k; cin >> n >> k;
    int o = (k & 1) ? k - 1 : k;
    int j = !(k & 1) ? k - 1 : k;
    int ret{0};
    if(n & 1)
    {
        n -= j;
        ret++;
    }
    ret += ((max(0, n) + o - 1) / o);
    cout << ret << endl;
}

int main()
{
    fast_io();
    int t = 1;
    cin >> t;
    while (t--)
    {
        solve();
    }
    return 0;
}
