//     while (ch < '0' || ch > '9')
//     {
//         if (ch == '-')
//             flag = -1;
//         ch = getchar_unlocked();
//     }

//     while (ch >= '0' && ch <= '9')
//     {
//         ret = ret * 10 + ch - '0';
//         ch = getchar_unlocked();
//     }

//     return ret * flag;
// }
// void print(LL x)
// {
//     if (x < 0)
//     {
//         putchar('-');
//         x = -x;
//     }
//     if (x > 9)
//         print(x / 10);
//     putchar(x % 10 + '0');
// }

int dx4[4] = {0, 0, -1, 1};
int dy4[4] = {1, -1, 0, 0};
int dx8[8] = {-1, -1, -1, 0, 1, 1, 1, 0};
int dy8[8] = {-1, 0, 1, 1, 1, 0, -1, -1};

// 一些常用的宏定义
#define PII pair<int, int>
#define PLL pair<LL, LL>
#define TIII tuple<int, int, int>
#define TLLL tuple <LL, LL, LL>
#define VVI vector<vector<int>>
#define VVLL vector<vector<LL>>
#define VI vector<int>
#define VLL vector<LL>
#define VPII vector<pair<int, int>>
#define VPLL vector<pair<LL, LL>>


const int N = 1e5 + 10;

void solve()
{
    int n, k; cin >> n >> k;
    VI a(n, 0);
    int M = 0;
    int index = 0;
    priority_queue<int> heap;
    for(int i = 0; i < n; i++)
    {
        cin >> a[i];
        heap.push(a[i]);
        if(a[i] > M)
        {
            M = a[i];
            index = i;
        }
    }

    if(k == 1)
    {
        if(index == n - 1 || !index)
        {
            heap.pop();
            cout << heap.top() + M << endl;
            return;
        }
        cout << M + max(a[0], a[n - 1]) << endl;
        return;
    }
    LL sum{0};
    k++;
    while(k--)
    {
        sum += heap.top();
        heap.pop();
    }
    cout << sum << endl;

}

int main()
{
    fast_io();
    int t = 1;
    cin >> t;
    while (t--)
    {
        solve();
    }
    return 0;
}
```


### C. Two Colors

[**点击这里传送到题目**](https://codeforces.com/contest/2075/problem/C)

#### 题目大意
> 给一排数量为n的木板，用m种颜料为整排木板染色，颜料数量有限制，整排木板只能恰好用两种颜色染色，并且两种颜色区间必须连续
> 求方案总数

#### 思路
> 一个较难的c题，神秘
> 我们可以注意到这里存在镜像情况，假如有十块木板

- oooxxxxxxx
- xxxooooooo
> 他们的方案数完全相同，所以这里可以只考虑前半部分，枚举第一种颜色的使用数量：
`for(int i = 1; i <= n - i; i++)`
>当两种颜色使用数量相同时不用翻倍
> 所以在这个枚举语境下，我们需要快速得知有多少种颜料满足我的使用需求，这里可以用个差分计算对于每种需求有几种颜料满足我的条件
```cpp
for(int i = 1; i <= m; i++)
{
    cin >> a[i];
    num[a[i]]++;
}

for(int i = n - 1; i >= 1; i--)
{
    num[i] += num[i + 1];
}
```
> 每次读入一种颜料的数量就表示0~a[i]范围内的需求满足数量++
> 因为这里控制了变量，第一种颜色需求数量不大于第二种颜色需求数量，所以可以把满足较少数量但够不着较大数量的拆出来
```cpp
LL x = num[i] - num[n - i];
LL y = num[n - i];
```
> 方案数量就可以这么计算，x和y中各选一个，也可以全在y里选，也就是在y里选两个颜色的排列
```cpp
for(int i = 1; i <= n - i; i++)
{
    LL x = num[i] - num[n - i];
    LL y = num[n - i];
    if(i != n - i) ans += (x * y + y * (y - 1)) * 2;
    else ans += x * y + y * (y - 1);
}
```

#### Final AC Code
```cpp
