//         if (ch == '-')
//             flag = -1;
//         ch = getchar_unlocked();
//     }

//     while (ch >= '0' && ch <= '9')
//     {
//         ret = ret * 10 + ch - '0';
//         ch = getchar_unlocked();
//     }

//     return ret * flag;
// }
// void print(LL x)
// {
//     if (x < 0)
//     {
//         putchar('-');
//         x = -x;
//     }
//     if (x > 9)
//         print(x / 10);
//     putchar(x % 10 + '0');
// }

int dx4[4] = {0, 0, -1, 1};
int dy4[4] = {1, -1, 0, 0};
int dx8[8] = {-1, -1, -1, 0, 1, 1, 1, 0};
int dy8[8] = {-1, 0, 1, 1, 1, 0, -1, -1};

// 一些常用的宏定义
#define PII pair<int, int>
#define PLL pair<LL, LL>
#define TIII tuple<int, int, int>
#define TLLL tuple <LL, LL, LL>
#define VVI vector<vector<int>>
#define VVLL vector<vector<LL>>
#define VI vector<int>
#define VLL vector<LL>
#define VPII vector<pair<int, int>>
#define VPLL vector<pair<LL, LL>>


const int N = 1e5 + 10;

void solve()
{
    int n, m; cin >> n >> m;
    VI a(m + 1, 0);
    VLL num(n + 1, 0);
    for(int i = 1; i <= m; i++)
    {
        cin >> a[i];
        num[a[i]]++;
    }
    for(int i = n - 1; i >= 1; i--)
    {
        num[i] += num[i + 1];
    }

    LL ans{0};
    for(int i = 1; i <= n - i; i++)
    {
        LL x = num[i] - num[n - i];
        LL y = num[n - i];
        if(i != n - i) ans += (x * y + y * (y - 1)) * 2;
        else ans += x * y + y * (y - 1);
    }
    cout << ans << endl;
}

int main()
{
    fast_io();
    int t = 1;
    cin >> t;
    while (t--)
    {
        solve();
    }
    return 0;
}
```


D. Equalization

[**点击这里传送到题目**](https://codeforces.com/contest/2075/problem/D)

#### 题目大意
> 给两个自然数x和y，可执行任意次操作：

- 选择一个正整数k
- 将x或y其中一个右移k位
- 成本为2^k
- k不能重复使用
> 计算让x等于y的最小总成本

#### 思路
> 看到k不能重复利用，有感觉这题贪心不太靠谱，自然就想到01背包
> 所以两个自然数的二进制表示可以分割为公共前缀部分和剩余部分，例如

- 101010010110
- 1010110010
> 公共前缀长度为5，前者剩余7，后者剩余5
> 建模为在1 - k正整数序列中选取数字填满容量分别为7和5的背包，代价最小

- 状态表示：`f[i][j][k]` 背包1填充i，背包2填充j，考虑0 - k的数字，代价最小值
- 初始化：`f[0][0][any_k] = 0`，`memset(f, 0x3f, sizeof(f));`
- 状态转移
```cpp
LL& t = f[i][j][k];
t = f[i][j][k - 1];
if(i >= k) t = min(t, f[i - k][j][k - 1] + (1ll << k));
if(j >= k) t = min(t, f[i][j - k][k - 1] + (1ll << k));
```
- 填表顺序：正常从小到大三重循环
- 答案获取 `f[][][30]`

> 两个正整数上限为1e17，60位够用了，把两者都右移至0最多也就120左右次，k为30就够用了
> 打完dp表之后，刨除一些简单的特判情况后，需要知道两个数的二进制公共前缀
> 最少要把两个数的剩余长度右移之后，公共前缀也可以往右移动，还有两个数字已经移动至0之后还能任意移动至长度上限，在这所有情况中取一个最小值就是最终答案

