#define VPLL vector<pair<LL, LL>>


const int N = 65, M = 35, inf = 0x3f3f3f3f;
const LL INF = 0x3f3f3f3f3f3f3f3f;
LL f[N][N][M];


void init(void)
{
    memset(f, 0x3f, sizeof(f));
    for(int i = 0; i <= 60; i++)  
    {
        for(int j = 0; j <= 60; j++)
        {
            for(int k = 0; k <= 30; k++)
            {
                if(i + j == 0) f[i][j][k] = 0;
                else if(k)
                {
                    LL& t = f[i][j][k];
                    t = f[i][j][k - 1];
                    if(i >= k) t = min(t, f[i - k][j][k - 1] + (1ll << k));
                    if(j >= k) t = min(t, f[i][j - k][k - 1] + (1ll << k));
                }
            }
        }

    }
}

void solve()
{
    LL x, y; cin >> x >> y;
    if(x == y) 
    {
        cout << 0 << endl;
        return;
    }
    int l1 = 0, l2 = 0;
    if(x == 0 || y == 0)
    {
        l2 = 64 - __builtin_clzll(x + y);
        cout << f[0][l2][30] << endl;
        return;
    }
    VI a, b;
    while(x)
    {
        a.push_back(x % 2);
        x /= 2;
    }
    while(y)
    {
        b.push_back(y % 2);
        y /= 2;
    }
    int si = -1;
    for(int i = 0; i < a.size() && i < b.size(); i++)
    {
        if(a[a.size() - 1 - i] == b[b.size() - 1 - i]) si = i;
        else break;
    }
    si++;
    l1 = a.size() - si;
    l2 = b.size() - si;
    LL res = INF;
    for(int i = 0; i < si; i++)
    {
        res = min(res, f[l1 + i][l2 + i][30]);
    }
    for(int i = a.size(); i <= 60; i++)
    {
        for(int j = b.size(); j <= 60; j++)
        {
            res = min(res, f[i][j][30]);
        }
    }
    cout << res << endl;
}

int main()
{
    fast_io();
    init();
    int t = 1;
    cin >> t;
    while (t--)
    {
        solve();
    }
    return 0;
}
